using Microsoft.EntityFrameworkCore;

// Cosmos DB provider fixes for EF Core 9:
// 1. Discriminator property renamed from "Discriminator" to "$type" — preserve old name for existing documents
// 2. id property no longer contains discriminator — preserve old format for existing documents
// 3. Sync I/O no longer supported — use async equivalents

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: Preserve the old "Discriminator" property name for existing documents.
        // EF Core 9 changed the default to "$type"; without this, existing queries fail.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: Preserve the old compound id format ("Session|<key>") for existing documents.
        // EF Core 9 changed id to contain only the key value; without this, point-reads fail.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

// Fix 3: Sync I/O example — synchronous Cosmos queries now throw.
// Before (BREAKS in EF Core 9):
//   var sessions = db.Sessions.ToList();
//   db.SaveChanges();
//
// After (use async equivalents):
//   var sessions = await db.Sessions.ToListAsync();
//   await db.SaveChangesAsync();

class CosmosQueryService
{
    // All Cosmos DB queries must be async in EF Core 9
    async Task<List<Session>> GetSessionsAsync(CosmosDbContext db)
    {
        return await db.Sessions.ToListAsync();
    }

    async Task SaveSessionAsync(CosmosDbContext db, Session session)
    {
        db.Sessions.Add(session);
        await db.SaveChangesAsync();
    }
}

